import{c as e,Q as i,j as t,m as s}from"./chunks/framework.DVkeSyfh.js";const b=JSON.parse('{"title":"Classifiers and Rhythm Lab","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/classifiers-and-rhythm-lab.md","filePath":"concepts/classifiers-and-rhythm-lab.md","lastUpdated":null}'),r={name:"concepts/classifiers-and-rhythm-lab.md"};function o(n,a,l,d,c,h){return i(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="classifiers-and-rhythm-lab" tabindex="-1">Classifiers and Rhythm Lab <a class="header-anchor" href="#classifiers-and-rhythm-lab" aria-label="Permalink to &quot;Classifiers and Rhythm Lab&quot;">​</a></h1><p>Audience: Rhythm Lab users and developers<br> Goal: explain labels, training artifacts, promotion, and scoring<br> Type: explanation</p><p>Rhythm Lab is the labeling and training side of the classifier workflow. The main app consumes promoted classifier models and stores scores.</p><h2 id="two-databases" tabindex="-1">Two databases <a class="header-anchor" href="#two-databases" aria-label="Permalink to &quot;Two databases&quot;">​</a></h2><p>The main library database stores tracks, metadata, analysis inputs, likes, and promoted classifier scores.</p><p>The lab database stores classifier labels, predictions, training checkpoints, and active-learning queues. Lab state lives under <code>tools/rhythm-lab/data/</code> by default.</p><h2 id="profile-types" tabindex="-1">Profile types <a class="header-anchor" href="#profile-types" aria-label="Permalink to &quot;Profile types&quot;">​</a></h2><ul><li><code>binary</code>: one positive label, one negative label, optional review labels.</li><li><code>multiclass</code>: user-defined class labels; one current class per track for the active profile.</li></ul><h2 id="training-inputs" tabindex="-1">Training inputs <a class="header-anchor" href="#training-inputs" aria-label="Permalink to &quot;Training inputs&quot;">​</a></h2><p>Training benchmarks SONARA, MERT, MAEST, and combined feature sets. Combined training requires SONARA features plus MERT and MAEST embeddings.</p><h2 id="promotion" tabindex="-1">Promotion <a class="header-anchor" href="#promotion" aria-label="Permalink to &quot;Promotion&quot;">​</a></h2><p>Promotion copies the selected combined artifact into <code>models/classifiers/&lt;artifact-prefix&gt;/</code> for the main app. Runtime scoring reads the promoted manifest and writes scores scoped by classifier key.</p><h2 id="calibration" tabindex="-1">Calibration <a class="header-anchor" href="#calibration" aria-label="Permalink to &quot;Calibration&quot;">​</a></h2><p>Calibration is opt-in. <code>--calibrate</code> attempts calibrated training when there are enough labels. <code>promote --require-calibration</code> should be used only when calibrated production behavior is intentionally required.</p>',14)])])}const m=e(r,[["render",o]]);export{b as __pageData,m as default};
